from itertools import permutations

class Solution:
    def canMakePalindromeQueries(self, s, queries):
        n = len(s)
        res = []
        for a, b, c, d in queries:
            left_idx = list(range(a, b + 1))
            right_idx = list(range(c, d + 1))
            left_chars = [s[i] for i in left_idx]
            right_chars = [s[i] for i in right_idx]
            left_opts = set(permutations(left_chars))
            right_opts = set(permutations(right_chars))
            found = False
            for lp in left_opts:
                trial = list(s)
                for pos, ch in zip(left_idx, lp):
                    trial[pos] = ch
                for rp in right_opts:
                    for pos, ch in zip(right_idx, rp):
                        trial[pos] = ch
                    ok = True
                    for i in range(n // 2):
                        if trial[i] != trial[n - 1 - i]:
                            ok = False
                            break
                    if ok:
                        found = True
                        break
                if found:
                    break
            res.append(found)
        return res

