var canMakePalindromeQueries = function(s, queries) {
    const n = s.length;
    const half = Math.floor(n / 2);
    const A = 97;
    const pref = [];
    for (let c = 0; c < 26; c++) {
        const ch = String.fromCharCode(A + c);
        const arr = new Int32Array(n + 1);
        let run = 0;
        for (let i = 0; i < n; i++) {
            if (s[i] === ch) run++;
            arr[i + 1] = run;
        }
        pref.push(arr);
    }
    const mismPref = new Int32Array(half + 1);
    for (let i = 0; i < half; i++) {
        mismPref[i + 1] = mismPref[i] + (s[i] !== s[n - 1 - i] ? 1 : 0);
    }
    const totalMismatch = mismPref[half];

    function cnt(arr, l, r) {
        if (l > r) return 0;
        return arr[r + 1] - arr[l];
    }

    const res = [];
    for (const [a, b, c, d] of queries) {
        const lo = Math.max(a, n - 1 - d);
        const hi = Math.min(b, n - 1 - c);
        const interEmpty = lo > hi;

        const mismatchLr = cnt(mismPref, a, b);
        const mismatchRr = cnt(mismPref, n - 1 - d, n - 1 - c);
        const mismatchInter = interEmpty ? 0 : cnt(mismPref, lo, hi);
        const mismatchOutside = totalMismatch - (mismatchLr + mismatchRr - mismatchInter);
        if (mismatchOutside !== 0) {
            res.push(false);
            continue;
        }

        let ok = true;
        for (let chIdx = 0; chIdx < 26; chIdx++) {
            const arr = pref[chIdx];
            const cl = cnt(arr, a, b);
            const cr = cnt(arr, c, d);
            const fFull = cnt(arr, n - 1 - b, n - 1 - a);
            const fInter = interEmpty ? 0 : cnt(arr, n - 1 - hi, n - 1 - lo);
            const fTarget = fFull - fInter;
            const gFull = cnt(arr, n - 1 - d, n - 1 - c);
            const gInter = interEmpty ? 0 : cnt(arr, lo, hi);
            const gTarget = gFull - gInter;
            if (fTarget > cl || gTarget > cr || (cl - fTarget) !== (cr - gTarget)) {
                ok = false;
                break;
            }
        }
        res.push(ok);
    }
    return res;
};
